import numpy as np
def __ref_kmeans(X, C0, n_iters):
    C = C0.astype(float).copy()
    for _ in range(n_iters):
        d2 = ((X[:, None, :] - C[None, :, :]) ** 2).sum(-1)
        assign = d2.argmin(axis=1)
        for j in range(len(C)):
            pts = X[assign == j]
            if len(pts) > 0:
                C[j] = pts.mean(axis=0)
    return C

import numpy as np
def __ref_pca(X, k):
    Xc = X - X.mean(axis=0)
    _, _, Vt = np.linalg.svd(Xc, full_matrices=False)
    V = Vt[:k]
    for i in range(len(V)):
        j = np.argmax(np.abs(V[i]))
        if V[i, j] < 0:
            V[i] = -V[i]
    return V

import numpy as np
def __ref_xent(Z, y):
    Zs = Z - Z.max(axis=1, keepdims=True)
    lse = np.log(np.exp(Zs).sum(axis=1))
    return float(np.mean(lse - Zs[np.arange(len(y)), y]))
